#!/usr/bin/env bash
set -euo pipefail
source "$(dirname "$0")/lib/common.sh"
serial=emulator-5554; package=org.archphene.linux.p0392be9c9f103a39d951c2f39c3644d2; while (($#)); do case "$1" in --serial) serial="${2:?}"; shift 2;; --package) package="${2:?}"; shift 2;; *) archphene_die "unknown argument: $1";; esac; done; archphene_init_adb "$serial"; safe="$(sed 's/[^A-Za-z0-9._-]/_/g' <<<"$serial")"; mkdir -p "$ARCHPHENE_ROOT/tooling/build"; before="$ARCHPHENE_ROOT/tooling/build/kcalc-calculation-before-$safe.png"; after="$ARCHPHENE_ROOT/tooling/build/kcalc-calculation-after-$safe.png"; activity="$(archphene_adb_run shell cmd package resolve-activity --brief -a android.intent.action.MAIN -c android.intent.category.LAUNCHER "$package" | tail -n1 | tr -d '\r')"; [[ "$activity" == */* ]] || archphene_die "could not resolve launcher activity for $package"
archphene_adb_run shell am force-stop "$package"; archphene_adb_run shell am start -n "$activity" >/dev/null; sleep 8; archphene_adb_run shell screencap -p /sdcard/kcalc-before.png; archphene_adb_run pull /sdcard/kcalc-before.png "$before" >/dev/null; for key in 8 81 9 70; do archphene_adb_run shell input keyevent "$key"; sleep 0.25; done; sleep 2; archphene_adb_run shell screencap -p /sdcard/kcalc-after.png; archphene_adb_run pull /sdcard/kcalc-after.png "$after" >/dev/null; changed="$({ cmp -l "$before" "$after" 2>/dev/null || true; } | awk 'NR <= 1000 { count++ } END { print count + 0 }')"; ((changed>=10)) || archphene_die "KCalc display did not visibly change after 1 + 2 = ($changed samples)"
app_pid="$(archphene_android_pid "$package")"; payload_pid="$(archphene_linux_loader_pid "$app_pid")"; [[ -n "$payload_pid" ]] || archphene_die "KCalc patched-glibc descendant is not owned by Android process $app_pid"; log="$(archphene_adb_run logcat -d -s ArchpheneInput:V '*:S')"; ! archphene_regex_contains "$log" 'protocol error|native dispatch failed' || archphene_die 'KCalc calculation triggered compositor failure'; archphene_note "KCalc calculation passed on $serial: changed $changed samples; child PID $payload_pid."
